import React, { useState, useEffect, useRef, useCallback } from 'react';
import axios from 'axios';
import {
  MessageCircle, Send, User, Search, Phone, PhoneOff,
  Settings, Save, X, Circle, Mic, MicOff, Shield,
  Image, Trash2, CheckSquare, Square, Download
} from 'lucide-react';

const WS_BASE = window.location.protocol === 'https:' ? 'wss://' : 'ws://';
const WS_HOST = window.location.host;

const AudioPlayerAdmin = ({ src }) => {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const toggle = () => {
    if (!audioRef.current) return;
    if (playing) audioRef.current.pause(); else audioRef.current.play();
    setPlaying(!playing);
  };
  return (
    <div className="flex items-center gap-2 mt-1">
      <audio ref={audioRef} src={src} onEnded={() => setPlaying(false)} />
      <button onClick={toggle} className="w-7 h-7 rounded-full bg-white/20 flex items-center justify-center hover:bg-white/30 text-xs">
        {playing ? '⏸' : '▶'}
      </button>
      <span className="text-xs opacity-70">Áudio</span>
    </div>
  );
};

const ChatAtendimento = () => {
  const [sessoes, setSessoes] = useState([]);
  const [sessaoSelecionada, setSessaoSelecionada] = useState(null);
  const [mensagens, setMensagens] = useState([]);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [busca, setBusca] = useState('');
  const [filtro, setFiltro] = useState('todas');
  const [loading, setLoading] = useState(false);
  const [showConfig, setShowConfig] = useState(false);
  const [config, setConfig] = useState({
    p2p_enabled: false, horario_inicio: '09:00', horario_fim: '18:00',
    dias_atendimento: [1, 2, 3, 4, 5], mensagem_fora_horario: '', mensagem_boas_vindas: '',
  });

  // P2P / gravação de chamada
  const [inCall, setInCall] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const callRecorderRef = useRef(null);
  const callChunksRef = useRef([]);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);
  const remoteAudioRef = useRef(null);

  // Gravação de áudio (mensagem)
  const [isRecordingAudio, setIsRecordingAudio] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const audioRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const recordingTimerRef = useRef(null);

  // Seleção de conversas
  const [selectMode, setSelectMode] = useState(false);
  const [selectedSessoes, setSelectedSessoes] = useState(new Set());

  const wsRef = useRef(null);
  const messagesEndRef = useRef(null);
  const pollRef = useRef(null);
  const imageInputRef = useRef(null);

  const loadSessoes = useCallback(async () => {
    try {
      const res = await axios.get('/api/admin/chat/sessoes');
      setSessoes(res.data || []);
    } catch (e) { console.error('Erro ao carregar sessões:', e); }
  }, []);

  const loadMensagens = useCallback(async (sessaoId) => {
    try {
      const res = await axios.get(`/api/admin/chat/sessao/${sessaoId}/mensagens`);
      setMensagens(res.data || []);
    } catch (e) { console.error('Erro ao carregar mensagens:', e); }
  }, []);

  const loadConfig = useCallback(async () => {
    try { const res = await axios.get('/api/admin/chat/config'); setConfig(res.data || {}); } catch (e) {}
  }, []);

  // WebSocket
  useEffect(() => {
    const token = localStorage.getItem('adminToken');
    if (!token) return;
    const url = `${WS_BASE}${WS_HOST}/ws/chat/admin?token=${token}`;
    const ws = new WebSocket(url);
    wsRef.current = ws;
    ws.onmessage = (evt) => {
      try {
        const data = JSON.parse(evt.data);
        if (data.type === 'nova_mensagem') {
          setMensagens(prev => [...prev, data]);
          loadSessoes();
        }
        if (data.type === 'webrtc_offer' || data.type === 'webrtc_answer' || data.type === 'webrtc_ice') {
          handleWebRTCSignal(data);
        }
      } catch (e) {}
    };
    return () => { ws.close(); };
  }, [loadSessoes]);

  useEffect(() => {
    loadSessoes(); loadConfig();
    pollRef.current = setInterval(loadSessoes, 5000);
    return () => clearInterval(pollRef.current);
  }, [loadSessoes, loadConfig]);

  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [mensagens]);

  const handleSelectSessao = async (s) => {
    if (selectMode) {
      setSelectedSessoes(prev => {
        const next = new Set(prev);
        if (next.has(s.sessao_id)) next.delete(s.sessao_id); else next.add(s.sessao_id);
        return next;
      });
      return;
    }
    setSessaoSelecionada(s);
    await loadMensagens(s.sessao_id);
  };

  const handleEnviar = async (e) => {
    e.preventDefault();
    if (!novaMensagem.trim() || !sessaoSelecionada) return;
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: 'mensagem', sessao_id: sessaoSelecionada.sessao_id, mensagem: novaMensagem }));
      setNovaMensagem('');
    } else {
      try {
        await axios.post('/api/admin/chat/mensagem', { sessao_id: sessaoSelecionada.sessao_id, mensagem: novaMensagem });
        setNovaMensagem('');
        loadMensagens(sessaoSelecionada.sessao_id);
      } catch (err) { alert('Erro ao enviar: ' + (err.response?.data?.detail || 'Erro')); }
    }
  };

  const handleEncerrar = async () => {
    if (!sessaoSelecionada || !window.confirm('Encerrar esta sessão?')) return;
    try {
      await axios.post(`/api/admin/chat/encerrar/${sessaoSelecionada.sessao_id}`);
      setSessaoSelecionada(null); setMensagens([]); loadSessoes();
    } catch (err) { alert('Erro: ' + (err.response?.data?.detail || 'Erro')); }
  };

  // Excluir conversas selecionadas
  const handleDeleteSelected = async () => {
    if (selectedSessoes.size === 0) return;
    if (!window.confirm(`Excluir ${selectedSessoes.size} conversa(s) permanentemente?`)) return;
    try {
      await axios.post('/api/admin/chat/excluir-conversas', { sessao_ids: Array.from(selectedSessoes) });
      setSelectedSessoes(new Set());
      setSelectMode(false);
      if (sessaoSelecionada && selectedSessoes.has(sessaoSelecionada.sessao_id)) {
        setSessaoSelecionada(null); setMensagens([]);
      }
      loadSessoes();
    } catch (err) { alert('Erro: ' + (err.response?.data?.detail || 'Erro')); }
  };

  const handleSaveConfig = async () => {
    setLoading(true);
    try { await axios.post('/api/admin/chat/config', config); alert('Configuração salva!'); setShowConfig(false); }
    catch (err) { alert('Erro: ' + (err.response?.data?.detail || 'Erro')); }
    finally { setLoading(false); }
  };

  // Image upload
  const handleImageUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file || !sessaoSelecionada) return;
    const fd = new FormData();
    fd.append('file', file);
    try {
      await axios.post(`/api/admin/chat/imagem/${sessaoSelecionada.sessao_id}`, fd, { headers: { 'Content-Type': 'multipart/form-data' } });
      loadMensagens(sessaoSelecionada.sessao_id);
    } catch (err) { alert('Erro ao enviar imagem: ' + (err.response?.data?.detail || 'Erro')); }
    e.target.value = '';
  };

  // Audio recording (WhatsApp-style message)
  const startAudioRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioChunksRef.current = [];
      const mr = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mr.ondataavailable = (e) => { if (e.data.size > 0) audioChunksRef.current.push(e.data); };
      mr.onstop = () => { stream.getTracks().forEach(t => t.stop()); };
      mr.start();
      audioRecorderRef.current = mr;
      setIsRecordingAudio(true); setRecordingTime(0);
      recordingTimerRef.current = setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (err) { alert('Erro ao acessar microfone: ' + err.message); }
  };

  const cancelAudioRecording = () => {
    if (audioRecorderRef.current?.state !== 'inactive') audioRecorderRef.current?.stop();
    clearInterval(recordingTimerRef.current);
    setIsRecordingAudio(false); setRecordingTime(0); audioChunksRef.current = [];
  };

  const sendAudioRecording = async () => {
    if (!audioRecorderRef.current || audioRecorderRef.current.state === 'inactive') return;
    audioRecorderRef.current.stop();
    clearInterval(recordingTimerRef.current);
    setIsRecordingAudio(false); setRecordingTime(0);
    await new Promise(r => setTimeout(r, 300));
    if (audioChunksRef.current.length === 0 || !sessaoSelecionada) return;
    const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
    const fd = new FormData();
    fd.append('file', blob, 'audio.webm');
    try {
      await axios.post(`/api/admin/chat/audio/${sessaoSelecionada.sessao_id}`, fd, { headers: { 'Content-Type': 'multipart/form-data' } });
      loadMensagens(sessaoSelecionada.sessao_id);
    } catch (err) { alert('Erro ao enviar áudio: ' + (err.response?.data?.detail || 'Erro')); }
  };

  const formatTime = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  // WebRTC P2P
  const handleWebRTCSignal = (data) => {
    if (data.type === 'webrtc_offer') startP2PAnswer(data);
    else if (data.type === 'webrtc_answer' && peerRef.current) peerRef.current.setRemoteDescription(new RTCSessionDescription(data.sdp));
    else if (data.type === 'webrtc_ice' && peerRef.current) peerRef.current.addIceCandidate(new RTCIceCandidate(data.candidate));
  };

  const startP2PCall = async () => {
    if (!sessaoSelecionada) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      peerRef.current = pc;
      stream.getTracks().forEach(t => pc.addTrack(t, stream));
      pc.ontrack = (e) => { if (remoteAudioRef.current) remoteAudioRef.current.srcObject = e.streams[0]; };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN)
          wsRef.current.send(JSON.stringify({ type: 'webrtc_ice', sessao_id: sessaoSelecionada.sessao_id, candidate: e.candidate }));
      };
      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      if (wsRef.current?.readyState === WebSocket.OPEN)
        wsRef.current.send(JSON.stringify({ type: 'webrtc_offer', sessao_id: sessaoSelecionada.sessao_id, sdp: offer }));
      setInCall(true);
    } catch (err) { alert('Erro ao iniciar chamada: ' + err.message); }
  };

  const startP2PAnswer = async (data) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      localStreamRef.current = stream;
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      peerRef.current = pc;
      stream.getTracks().forEach(t => pc.addTrack(t, stream));
      pc.ontrack = (e) => { if (remoteAudioRef.current) remoteAudioRef.current.srcObject = e.streams[0]; };
      pc.onicecandidate = (e) => {
        if (e.candidate && wsRef.current?.readyState === WebSocket.OPEN)
          wsRef.current.send(JSON.stringify({ type: 'webrtc_ice', sessao_id: data.sessao_id, candidate: e.candidate }));
      };
      await pc.setRemoteDescription(new RTCSessionDescription(data.sdp));
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);
      if (wsRef.current?.readyState === WebSocket.OPEN)
        wsRef.current.send(JSON.stringify({ type: 'webrtc_answer', sessao_id: data.sessao_id, sdp: answer }));
      setInCall(true);
      setSessaoSelecionada(prev => prev || sessoes.find(s => s.sessao_id === data.sessao_id));
    } catch (err) { console.error('Erro ao atender chamada:', err); }
  };

  const endCall = () => {
    peerRef.current?.close(); peerRef.current = null;
    localStreamRef.current?.getTracks().forEach(t => t.stop()); localStreamRef.current = null;
    setInCall(false); stopCallRecording();
  };

  // Gravação de chamada P2P
  const startCallRecording = () => {
    if (!localStreamRef.current) return;
    callChunksRef.current = [];
    try {
      const mr = new MediaRecorder(localStreamRef.current, { mimeType: 'audio/webm' });
      mr.ondataavailable = (e) => { if (e.data.size > 0) callChunksRef.current.push(e.data); };
      mr.start(); callRecorderRef.current = mr; setIsRecording(true);
    } catch (err) { alert('Erro ao iniciar gravação: ' + err.message); }
  };

  const stopCallRecording = async () => {
    if (!callRecorderRef.current || callRecorderRef.current.state === 'inactive') { setIsRecording(false); return; }
    callRecorderRef.current.stop(); setIsRecording(false);
    await new Promise(r => setTimeout(r, 500));
    if (callChunksRef.current.length === 0 || !sessaoSelecionada) return;
    const blob = new Blob(callChunksRef.current, { type: 'audio/webm' });
    const fd = new FormData();
    fd.append('file', blob, 'gravacao.webm');
    try {
      const res = await axios.post(`/api/admin/chat/gravar/${sessaoSelecionada.sessao_id}`, fd, { headers: { 'Content-Type': 'multipart/form-data' } });
      alert(`Gravação salva! Protocolo: ${res.data.protocolo}`);
      loadMensagens(sessaoSelecionada.sessao_id);
    } catch (err) { alert('Erro ao salvar gravação: ' + (err.response?.data?.detail || 'Erro')); }
  };

  // Render message content
  const renderMsgContent = (m) => {
    const extra = m.extra;
    if (extra?.tipo === 'audio') {
      return <AudioPlayerAdmin src={`/api/chat/audio/${extra.arquivo}`} />;
    }
    if (extra?.tipo === 'imagem') {
      return <img src={`/api/chat/imagem/${extra.arquivo}`} alt="Imagem" className="rounded-lg max-w-full max-h-48 cursor-pointer" onClick={() => window.open(`/api/chat/imagem/${extra.arquivo}`, '_blank')} />;
    }
    if (extra?.tipo === 'gravacao') {
      return (
        <div className="space-y-1">
          <p className="text-xs">📎 Gravação anexada</p>
          <div className="flex gap-2">
            <a href={`/api/admin/chat/gravacao/${extra.arquivo}`} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 text-xs bg-white/20 px-2 py-1 rounded hover:bg-white/30">
              <Download className="h-3 w-3" /> Baixar
            </a>
          </div>
        </div>
      );
    }
    return <p className="text-sm whitespace-pre-wrap">{m.mensagem}</p>;
  };

  const sessoesFiltradas = sessoes.filter((s) => {
    const matchBusca = !busca ||
      (s.cliente_nome || '').toLowerCase().includes(busca.toLowerCase()) ||
      (s.cliente_email || '').toLowerCase().includes(busca.toLowerCase()) ||
      (s.protocolo || '').toLowerCase().includes(busca.toLowerCase());
    const matchFiltro = filtro === 'todas' ||
      (filtro === 'ativas' && s.status === 'ativa') ||
      (filtro === 'encerradas' && s.status === 'encerrada');
    return matchBusca && matchFiltro;
  });

  const diasSemana = [
    { value: 1, label: 'Seg' }, { value: 2, label: 'Ter' }, { value: 3, label: 'Qua' },
    { value: 4, label: 'Qui' }, { value: 5, label: 'Sex' }, { value: 6, label: 'Sáb' }, { value: 7, label: 'Dom' },
  ];

  return (
    <div className="h-[calc(100vh-8rem)]">
      {showConfig && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-lg w-full p-6 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-gray-900">Configurações do Chat</h3>
              <button onClick={() => setShowConfig(false)}><X className="h-5 w-5 text-gray-400" /></button>
            </div>
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-gray-700">Ligação P2P habilitada</label>
                <button onClick={() => setConfig({ ...config, p2p_enabled: !config.p2p_enabled })} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${config.p2p_enabled ? 'bg-green-500' : 'bg-gray-300'}`}>
                  <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${config.p2p_enabled ? 'translate-x-6' : 'translate-x-1'}`} />
                </button>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Horário início</label>
                  <input type="time" value={config.horario_inicio} onChange={(e) => setConfig({ ...config, horario_inicio: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Horário fim</label>
                  <input type="time" value={config.horario_fim} onChange={(e) => setConfig({ ...config, horario_fim: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Dias de atendimento</label>
                <div className="flex gap-2 flex-wrap">
                  {diasSemana.map((d) => (
                    <button key={d.value} onClick={() => { const dias = config.dias_atendimento || []; setConfig({ ...config, dias_atendimento: dias.includes(d.value) ? dias.filter(x => x !== d.value) : [...dias, d.value] }); }}
                      className={`px-3 py-1 rounded-full text-xs font-medium ${(config.dias_atendimento || []).includes(d.value) ? 'bg-blue-500 text-white' : 'bg-gray-100 text-gray-600'}`}>{d.label}</button>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Mensagem de boas-vindas</label>
                <textarea value={config.mensagem_boas_vindas} onChange={(e) => setConfig({ ...config, mensagem_boas_vindas: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" rows={2} />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Mensagem fora do horário</label>
                <textarea value={config.mensagem_fora_horario} onChange={(e) => setConfig({ ...config, mensagem_fora_horario: e.target.value })} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm" rows={2} />
              </div>
              <button onClick={handleSaveConfig} disabled={loading} className="w-full bg-blue-600 text-white font-medium py-2 rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center justify-center gap-2">
                <Save className="h-4 w-4" /> Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      <audio ref={remoteAudioRef} autoPlay />
      <input type="file" ref={imageInputRef} accept="image/*" style={{ display: 'none' }} onChange={handleImageUpload} />

      <div className="bg-white rounded-lg shadow h-full flex">
        {/* Lista lateral */}
        <div className="w-80 border-r border-gray-200 flex flex-col">
          <div className="p-3 border-b border-gray-200">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                <MessageCircle className="h-5 w-5 text-blue-600" /> Chat
              </h2>
              <div className="flex items-center gap-1">
                <button onClick={() => { setSelectMode(!selectMode); setSelectedSessoes(new Set()); }} className={`p-1 rounded hover:bg-gray-100 ${selectMode ? 'bg-blue-100 text-blue-600' : ''}`} title="Selecionar conversas">
                  <CheckSquare className="h-5 w-5 text-gray-500" />
                </button>
                <button onClick={() => { loadConfig(); setShowConfig(true); }} className="p-1 rounded hover:bg-gray-100">
                  <Settings className="h-5 w-5 text-gray-500" />
                </button>
              </div>
            </div>

            {selectMode && selectedSessoes.size > 0 && (
              <button onClick={handleDeleteSelected} className="w-full mb-2 bg-red-500 text-white text-sm font-medium py-1.5 rounded-lg hover:bg-red-600 flex items-center justify-center gap-2">
                <Trash2 className="h-4 w-4" /> Excluir {selectedSessoes.size} conversa(s)
              </button>
            )}

            <div className="relative mb-2">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input type="text" placeholder="Buscar..." value={busca} onChange={(e) => setBusca(e.target.value)} className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg text-sm" />
            </div>
            <select value={filtro} onChange={(e) => setFiltro(e.target.value)} className="w-full px-3 py-1.5 border border-gray-300 rounded-lg text-sm">
              <option value="todas">Todas</option>
              <option value="ativas">Ativas</option>
              <option value="encerradas">Encerradas</option>
            </select>
          </div>

          <div className="flex-1 overflow-y-auto">
            {sessoesFiltradas.length === 0 ? (
              <div className="p-4 text-center text-gray-400">
                <MessageCircle className="h-8 w-8 mx-auto mb-2" />
                <p className="text-sm">Nenhuma conversa</p>
              </div>
            ) : sessoesFiltradas.map((s) => (
              <div key={s.sessao_id} onClick={() => handleSelectSessao(s)}
                className={`p-3 cursor-pointer border-b border-gray-100 transition-colors ${sessaoSelecionada?.sessao_id === s.sessao_id && !selectMode ? 'bg-blue-50 border-l-4 border-l-blue-500' : 'hover:bg-gray-50'} ${selectMode && selectedSessoes.has(s.sessao_id) ? 'bg-red-50' : ''}`}>
                <div className="flex items-start gap-2">
                  {selectMode && (
                    <div className="pt-1">
                      {selectedSessoes.has(s.sessao_id) ? <CheckSquare className="h-4 w-4 text-red-500" /> : <Square className="h-4 w-4 text-gray-400" />}
                    </div>
                  )}
                  <div className="flex items-start justify-between flex-1 min-w-0">
                    <div className="flex items-center gap-2 min-w-0">
                      <div className="relative">
                        <div className="bg-gray-200 rounded-full p-1.5"><User className="h-4 w-4 text-gray-600" /></div>
                        {s.online && <Circle className="absolute -bottom-0.5 -right-0.5 h-3 w-3 text-green-500 fill-green-500" />}
                      </div>
                      <div className="min-w-0">
                        <p className="text-sm font-medium text-gray-900 truncate">{s.cliente_nome || 'Cliente'}</p>
                        <p className="text-xs text-gray-500 truncate">{s.protocolo || s.cliente_email}</p>
                      </div>
                    </div>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium flex-shrink-0 ${s.status === 'ativa' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                      {s.status === 'ativa' ? 'Ativo' : 'Encerrado'}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Chat area */}
        <div className="flex-1 flex flex-col">
          {sessaoSelecionada ? (
            <>
              <div className="p-3 border-b border-gray-200 bg-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="bg-blue-600 rounded-full p-2"><User className="h-4 w-4 text-white" /></div>
                  <div>
                    <p className="text-sm font-semibold text-gray-900">{sessaoSelecionada.cliente_nome || 'Cliente'}</p>
                    <p className="text-xs text-gray-500">{sessaoSelecionada.protocolo} · {sessaoSelecionada.cliente_email}</p>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  {config.p2p_enabled && !inCall && sessaoSelecionada.status === 'ativa' && (
                    <button onClick={startP2PCall} className="p-2 rounded-lg bg-green-500 text-white hover:bg-green-600" title="Iniciar chamada"><Phone className="h-4 w-4" /></button>
                  )}
                  {inCall && (
                    <>
                      <button onClick={endCall} className="p-2 rounded-lg bg-red-500 text-white hover:bg-red-600" title="Encerrar chamada"><PhoneOff className="h-4 w-4" /></button>
                      {!isRecording ? (
                        <button onClick={startCallRecording} className="p-2 rounded-lg bg-yellow-500 text-white hover:bg-yellow-600" title="Gravar chamada"><Mic className="h-4 w-4" /></button>
                      ) : (
                        <button onClick={stopCallRecording} className="p-2 rounded-lg bg-red-600 text-white hover:bg-red-700 animate-pulse" title="Parar gravação"><MicOff className="h-4 w-4" /></button>
                      )}
                    </>
                  )}
                  {sessaoSelecionada.status === 'ativa' && (
                    <button onClick={handleEncerrar} className="p-2 rounded-lg bg-gray-200 text-gray-600 hover:bg-gray-300" title="Encerrar sessão"><X className="h-4 w-4" /></button>
                  )}
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
                {mensagens.map((m, idx) => (
                  <div key={m.id || idx} className={`flex ${m.remetente === 'atendente' ? 'justify-end' : m.remetente === 'sistema' ? 'justify-center' : 'justify-start'}`}>
                    {m.remetente === 'sistema' ? (
                      <div className="bg-yellow-100 text-yellow-800 text-xs px-3 py-1.5 rounded-full max-w-sm text-center">
                        <Shield className="h-3 w-3 inline mr-1" />{m.mensagem}
                      </div>
                    ) : (
                      <div className={`max-w-xs lg:max-w-md px-4 py-2 rounded-2xl ${m.remetente === 'atendente' ? 'bg-blue-600 text-white rounded-br-md' : 'bg-white text-gray-900 shadow rounded-bl-md'}`}>
                        {renderMsgContent(m)}
                        <p className={`text-[10px] mt-1 ${m.remetente === 'atendente' ? 'text-blue-200' : 'text-gray-400'}`}>
                          {m.data_criacao ? new Date(m.data_criacao).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) : ''}
                        </p>
                      </div>
                    )}
                  </div>
                ))}
                <div ref={messagesEndRef} />
              </div>

              {/* Input area */}
              {sessaoSelecionada.status === 'ativa' && (
                isRecordingAudio ? (
                  <div className="p-3 border-t border-gray-200 bg-red-50">
                    <div className="flex items-center gap-2">
                      <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse" />
                      <span className="text-sm text-red-700 font-medium flex-1">Gravando... {formatTime(recordingTime)}</span>
                      <button onClick={cancelAudioRecording} className="p-2 bg-gray-200 rounded-full hover:bg-gray-300"><X className="h-4 w-4" /></button>
                      <button onClick={sendAudioRecording} className="p-2 bg-blue-600 rounded-full hover:bg-blue-700 text-white"><Send className="h-4 w-4" /></button>
                    </div>
                  </div>
                ) : (
                  <form onSubmit={handleEnviar} className="p-3 border-t border-gray-200 bg-white">
                    <div className="flex gap-1.5 items-center">
                      <button type="button" onClick={() => imageInputRef.current?.click()} className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full" title="Enviar imagem">
                        <Image className="h-4 w-4" />
                      </button>
                      <button type="button" onClick={startAudioRecording} className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full" title="Gravar áudio">
                        <Mic className="h-4 w-4" />
                      </button>
                      <input type="text" value={novaMensagem} onChange={(e) => setNovaMensagem(e.target.value)} placeholder="Digite sua mensagem..." className="flex-1 px-4 py-2 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm" />
                      <button type="submit" disabled={!novaMensagem.trim()} className="bg-blue-600 text-white p-2.5 rounded-full hover:bg-blue-700 disabled:opacity-50">
                        <Send className="h-4 w-4" />
                      </button>
                    </div>
                  </form>
                )
              )}
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center">
              <div className="text-center">
                <MessageCircle className="h-16 w-16 text-gray-200 mx-auto mb-4" />
                <p className="text-gray-400 text-lg">Selecione uma conversa</p>
                <p className="text-gray-300 text-sm mt-1">As mensagens aparecerão aqui</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChatAtendimento;
